arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // Fixed: EF Core 9 manages its own transactions during Migrate().
        // Wrapping in a user transaction now throws. Remove the explicit
        // transaction and execution strategy — Migrate() handles retries internally.
        db.Database.Migrate();
    }
}

